"""Интерфейс и реализация логгера пайплайна."""from __future__ import annotationsfrom pathlib import Pathfrom typing import Any, Callable, Protocolfrom src.core.logger import FileLoggerfrom src.core.logger.file_logger import _format_msgfrom src.modules.project.project_paths import ProjectPathsclass PipelineLoggerProtocol(Protocol):    """Контракт логгера для контекста этапа: info, warning, error и др."""    def debug(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...    def info(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...    def warning(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...    def error(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...    def exception(self, msg: Any, *args: Any, **kwargs: Any) -> None: ...class ProjectPipelineLogger:    """    Логгер пайплайна для одного проекта.    Пишет в файл проекта `paths.logs/pipeline.log` и опционально в GUI-консоль.    """    def __init__(        self,        project_root: Path,        *,        console_sink: Callable[[str], None] | None = None,    ) -> None:        paths = ProjectPaths.from_root(project_root)        self._file_logger = FileLogger(logs_dir=paths.logs, file_name="pipeline")        self._console_sink = console_sink    def _emit(self, level: str, msg: Any, *args: Any, **kwargs: Any) -> None:        getattr(self._file_logger, level)(msg, *args, **kwargs)        if self._console_sink is not None:            text = _format_msg(msg, *args, **kwargs)            self._console_sink(f"[{level.upper()}] {text}")    def debug(self, msg: Any, *args: Any, **kwargs: Any) -> None:        self._emit("debug", msg, *args, **kwargs)    def info(self, msg: Any, *args: Any, **kwargs: Any) -> None:        self._emit("info", msg, *args, **kwargs)    def warning(self, msg: Any, *args: Any, **kwargs: Any) -> None:        self._emit("warning", msg, *args, **kwargs)    def error(self, msg: Any, *args: Any, **kwargs: Any) -> None:        self._emit("error", msg, *args, **kwargs)    def exception(self, msg: Any, *args: Any, **kwargs: Any) -> None:        self._file_logger.exception(msg, *args, **kwargs)        if self._console_sink is not None:            text = _format_msg(msg, *args, **kwargs)            self._console_sink(f"[ERROR] {text}")